import streamlit as stfrom utils.crm_utils import detect_intent, generate_responsefrom utils.data_utils import get_risk_label, get_risk_colorSUGGESTIONS = [    "Mon vol va-t-il être en retard ?",    "Quelles compensations puis-je recevoir ?",    "Combien de miles vais-je obtenir ?",    "Comment contacter le service client ?",    "Quels sont mes droits en cas de retard ?",    "Y a-t-il des vols alternatifs ?",]def render_message(role, content):    if role == "bot":        st.markdown(f"""        <div class='chat-message'>            <div class='avatar bot'>🤖</div>            <div class='chat-bubble bot'>{content}</div>        </div>""", unsafe_allow_html=True)    else:        st.markdown(f"""        <div class='chat-message user'>            <div class='avatar user'>👤</div>            <div class='chat-bubble user'>{content}</div>        </div>""", unsafe_allow_html=True)def render():    st.markdown("""    <div class='page-header'>        <h1>💬 Assistant IA — IMSD CRM</h1>        <p>Posez vos questions sur votre vol et vos droits</p>    </div>""", unsafe_allow_html=True)    last_pred = st.session_state.get("last_prediction", None)    with st.sidebar:        st.markdown("### ✈️ Vol actif")        if last_pred:            label,css = get_risk_label(last_pred["proba"])            color     = get_risk_color(last_pred["proba"])            st.markdown(f"""            <div class='risk-card {css}'>                <div style='font-weight:700;'>{last_pred.get('ap_dep','?')} → {last_pred.get('ap_arr','?')}</div>                <div style='color:#6B7280;font-size:0.8rem;'>{last_pred.get('compagnie','?')}</div>                <hr style='border-color:#1F2937;margin:8px 0;'>                <div style='font-size:1.4rem;font-weight:700;color:{color};'>                    {last_pred['proba']*100:.1f}% {label}                </div>            </div>""", unsafe_allow_html=True)        else:            st.info("Analysez d'abord un vol dans **Prédiction**.")        st.markdown("---")        if st.button("🗑️ Effacer la conversation"):            st.session_state["chat_history"] = []            st.rerun()    if "chat_history" not in st.session_state:        proba = last_pred["proba"] if last_pred else None        comp  = last_pred.get("compagnie","votre compagnie") if last_pred else "votre compagnie"        st.session_state["chat_history"] = [            {"role":"bot","content": generate_response("general", proba, compagnie=comp)}        ]    for msg in st.session_state["chat_history"]:        render_message(msg["role"], msg["content"])    st.markdown("<br>**💡 Questions fréquentes :**", unsafe_allow_html=True)    cols = st.columns(3)    for i,sug in enumerate(SUGGESTIONS):        with cols[i%3]:            if st.button(sug, key=f"sug_{i}", use_container_width=True):                st.session_state["pending_message"] = sug    with st.form("chat_form", clear_on_submit=True):        ci,cb = st.columns([5,1])        with ci:            user_input = st.text_input("Question", placeholder="Ex : Mon vol va-t-il être en retard ?",                                       label_visibility="collapsed")        with cb:            submitted = st.form_submit_button("Envoyer ➤", use_container_width=True)    pending = st.session_state.pop("pending_message", None)    msg_to_process = pending or (user_input if submitted and user_input else None)    if msg_to_process:        st.session_state["chat_history"].append({"role":"user","content":msg_to_process})        intent = detect_intent(msg_to_process)        proba  = last_pred["proba"]              if last_pred else None        dist   = last_pred.get("distance",1000)  if last_pred else 1000        comp   = last_pred.get("compagnie","votre compagnie") if last_pred else "votre compagnie"        resp   = generate_response(intent, proba, distance=dist, compagnie=comp)        st.session_state["chat_history"].append({"role":"bot","content":resp})        st.rerun()